<script setup lang="ts">
import {Head} from '@inertiajs/vue3';import{Archive,ArrowLeft,BellOff,Flag,Paperclip,Search,Settings,UserX,Volume2,X}from'@lucide/vue';import{computed,nextTick,onMounted,onUnmounted,ref,watch}from'vue';import AppShell from'../../Layouts/AppShell.vue';
const props=withDefaults(defineProps<{initialTab?:'messages'|'requests'}>(),{initialTab:'messages'}),user=(window as any).__user;
const archivedView=ref(new URLSearchParams(location.search).get('archived')==='1');
const conversations=ref<any[]>([]),requests=ref<any[]>([]),archivedCount=ref(0),tab=ref<'messages'|'requests'>(props.initialTab),active=ref<any>(),selectedRequest=ref<any>(),messages=ref<any[]>([]),draft=ref(''),attachment=ref<File|null>(null),loading=ref(true),sending=ref(false),typingName=ref(''),controls=ref(false),notice=ref(''),thread=ref<HTMLElement|null>(null),selectedMessage=ref<any>(),editText=ref(''),messageActionBusy=ref(false),mobileChatOpen=ref(false);let typingTimer:any,longPressTimer:any,channel:any;
const csrf=()=>(document.querySelector('meta[name="csrf-token"]')as HTMLMetaElement)?.content??'',me=computed(()=>((document.querySelector('meta[name="user-id"]')as HTMLMetaElement)?.content)),other=(c:any)=>c?.participants?.find((p:any)=>String(p.id)!==me.value)||c?.participants?.[0],initials=(n='')=>n.split(/\s+/).map(v=>v[0]).join('').slice(0,2).toUpperCase();
const messageSender=(message:any)=>active.value?.participants?.find((participant:any)=>String(participant.id)===String(message.sender?.id))??message.sender??{};
const api=async(url:string,options:RequestInit={})=>{const r=await fetch(url,{...options,credentials:'same-origin',headers:{Accept:'application/json','X-CSRF-TOKEN':csrf(),...(options.body instanceof FormData?{}:{'Content-Type':'application/json'}),...(options.headers??{})}}),body=r.status===204?{}:await r.json();if(!r.ok)throw new Error(body.message??'Request failed.');return body};
const bottom=async()=>{await nextTick();if(thread.value)thread.value.scrollTop=thread.value.scrollHeight};
const subscribe=(conversation:any)=>{if(channel&&active.value)window.Echo?.leave('conversations.'+active.value.id);channel=window.Echo?.private('conversations.'+conversation.id).listen('.message.sent',(event:any)=>{if(String(event.sender_id)===me.value)return;messages.value.push({...event,sender:{id:event.sender_id}});api('/api/v1/conversations/'+conversation.id+'/read',{method:'POST',body:'{}'});bottom()}).listen('.message.changed',(event:any)=>{const message=messages.value.find(item=>item.id===event.id);if(message)Object.assign(message,event)}).listen('.typing.updated',(event:any)=>{if(String(event.user_id)!==me.value){typingName.value=event.typing?event.name:'';clearTimeout(typingTimer);if(event.typing)typingTimer=setTimeout(()=>typingName.value='',2500)}}).listen('.conversation.read',(event:any)=>{if(String(event.user_id)!==me.value)messages.value.forEach(m=>{if(String(m.sender?.id)===me.value)m.read_at=event.read_at})})};
const select=async(c:any,revealMobile=true)=>{active.value=c;mobileChatOpen.value=revealMobile;messages.value=[...((await api('/api/v1/conversations/'+c.id+'/messages')).data??[])].reverse();await api('/api/v1/conversations/'+c.id+'/read',{method:'POST',body:'{}'});c.unread_count=0;subscribe(c);bottom()};
const openRequest=(request:any)=>{selectedRequest.value=request;mobileChatOpen.value=true};
const closeMobileChat=()=>{mobileChatOpen.value=false;controls.value=false};
const load=async()=>{const[c,r,a]=await Promise.all([api('/api/v1/conversations'+(archivedView.value?'?archived=1':'')),api('/api/v1/message-requests?status=pending'),archivedView.value?Promise.resolve(null):api('/api/v1/conversations?archived=1')]);conversations.value=c.data??[];requests.value=r.data??[];archivedCount.value=archivedView.value?(c.meta?.total??conversations.value.length):(a?.meta?.total??a?.data?.length??0);if(props.initialTab==='requests')selectedRequest.value=requests.value[0];else{const requested=new URLSearchParams(location.search).get('conversation'),conversation=conversations.value.find((item:any)=>item.id===requested)??conversations.value[0];if(conversation)await select(conversation,Boolean(requested))}loading.value=false};
const showInbox=()=>{if(archivedView.value)location.href='/messages';else{tab.value='messages';mobileChatOpen.value=false}};
const showRequests=()=>{tab.value='requests';mobileChatOpen.value=false};
const showArchived=()=>{if(archivedView.value)tab.value='messages';else location.href='/messages?archived=1'};
const upload=async(file:File)=>{const form=new FormData();form.append('file',file);form.append('kind',file.type.startsWith('video/')?'video':'image');form.append('collection','uploads');let media=(await api('/api/v1/media',{method:'POST',body:form})).data;for(let i=0;i<600&&['pending','processing'].includes(media.processing_status);i++){await new Promise(r=>setTimeout(r,1000));media=(await api('/api/v1/media/'+media.id)).data}if(media.processing_status!=='ready')throw new Error('Attachment processing failed.');return media.id};
const sendTyping=(typing:boolean)=>{if(active.value)api('/api/v1/conversations/'+active.value.id+'/typing',{method:'POST',body:JSON.stringify({typing})}).catch(()=>undefined)};
const send=async()=>{if((!draft.value.trim()&&!attachment.value)||!active.value||sending.value)return;sending.value=true;try{const mediaId=attachment.value?await upload(attachment.value):null,body=await api('/api/v1/conversations/'+active.value.id+'/messages',{method:'POST',body:JSON.stringify({body:draft.value.trim()||null,media_id:mediaId})});messages.value.push(body.data);draft.value='';attachment.value=null;sendTyping(false);bottom()}finally{sending.value=false}};
const openMessageControls=(message:any)=>{if(String(message.sender?.id)!==me.value||message.deleted_at)return;selectedMessage.value=message;editText.value=message.body??''};
const startMessagePress=(message:any)=>{clearTimeout(longPressTimer);if(String(message.sender?.id)===me.value&&!message.deleted_at)longPressTimer=setTimeout(()=>openMessageControls(message),550)};
const cancelMessagePress=()=>clearTimeout(longPressTimer);
const editMessage=async()=>{if(!selectedMessage.value||selectedMessage.value.read_at||!editText.value.trim())return;messageActionBusy.value=true;try{const response=await api('/api/v1/conversations/'+active.value.id+'/messages/'+selectedMessage.value.id,{method:'PATCH',body:JSON.stringify({body:editText.value.trim()})});Object.assign(selectedMessage.value,response.data);selectedMessage.value=null;notice.value='Message edited'}catch(error:any){notice.value=error.message}finally{messageActionBusy.value=false}};
const deleteMessage=async()=>{if(!selectedMessage.value||!confirm('Delete this message?'))return;messageActionBusy.value=true;try{const response=await api('/api/v1/conversations/'+active.value.id+'/messages/'+selectedMessage.value.id,{method:'DELETE'});Object.assign(selectedMessage.value,response.data);selectedMessage.value=null;notice.value='Message deleted'}catch(error:any){notice.value=error.message}finally{messageActionBusy.value=false}};
watch(draft,()=>{sendTyping(!!draft.value);clearTimeout(typingTimer);typingTimer=setTimeout(()=>sendTyping(false),1400)});
const act=async(action:'mute'|'archive'|'restore'|'report'|'block')=>{if(action==='mute'){const r=await api('/api/v1/conversations/'+active.value.id+'/mute',{method:'POST',body:JSON.stringify({muted:!active.value.muted})});active.value.muted=r.data.muted;notice.value=r.data.muted?'Conversation muted':'Conversation unmuted'}else if(action==='archive'){await api('/api/v1/conversations/'+active.value.id+'/archive',{method:'POST',body:'{}'});conversations.value=conversations.value.filter(c=>c.id!==active.value.id);active.value=null;notice.value='Conversation archived'}else if(action==='restore'){await api('/api/v1/conversations/'+active.value.id+'/archive',{method:'DELETE'});conversations.value=conversations.value.filter(c=>c.id!==active.value.id);active.value=null;notice.value='Conversation restored to Messages'}else if(action==='report'){await api('/api/v1/conversations/'+active.value.id+'/report',{method:'POST',body:JSON.stringify({reason:'other',details:'Reported from messaging'})});active.value.reported=true;notice.value='Conversation reported. It remains available as evidence.'}else{const person=other(active.value);if(person&&confirm(`Block ${person.name}? They will no longer be able to message or follow you.`)){await api('/api/v1/profiles/'+person.id+'/block',{method:'POST',body:JSON.stringify({reason:'Blocked from reported conversation'})});active.value.blocked=true;notice.value=`${person.name} has been blocked.`}}controls.value=false};
const respond=async(r:any,a:'accept'|'decline')=>{await api('/api/v1/message-requests/'+r.id+'/'+a,{method:'POST',body:'{}'});requests.value=requests.value.filter(i=>i.id!==r.id);selectedRequest.value=requests.value[0]};
const enablePush=async()=>{const p=await Notification.requestPermission();if(p!=='granted'){notice.value='Notification permission denied';return}const key=(document.querySelector('meta[name="vapid-public-key"]')as HTMLMetaElement)?.content;if(key&&'serviceWorker'in navigator){const registration=await navigator.serviceWorker.ready,padding='='.repeat((4-key.length%4)%4),raw=atob((key+padding).replace(/-/g,'+').replace(/_/g,'/')),bytes=Uint8Array.from([...raw].map(c=>c.charCodeAt(0))),subscription=await registration.pushManager.subscribe({userVisibleOnly:true,applicationServerKey:bytes});await api('/api/v1/push-subscriptions',{method:'POST',body:JSON.stringify(subscription.toJSON())})}notice.value='Push notifications enabled'};
onMounted(()=>{(window as any).__user=undefined;load()});onUnmounted(()=>{if(active.value)window.Echo?.leave('conversations.'+active.value.id);clearTimeout(typingTimer);clearTimeout(longPressTimer)});
</script>
<template><Head :title="props.initialTab==='requests'?'Message requests':archivedView?'Archived messages':'Messages'"/><AppShell><main class="messages-page"><header class="messages-heading"><div><h1>{{props.initialTab==='requests'?'Message requests':archivedView?'Archived conversations':'Messages'}}</h1><p>{{archivedView?'Review or restore conversations you archived.':'Real-time conversations with athletes, clubs and scouts.'}}</p></div><button class="push-enable" @click="enablePush"><Volume2/>Enable push</button></header><p v-if="notice" class="message-notice">{{notice}}</p><div class="messages-layout" :class="{'mobile-chat-open':mobileChatOpen}"><aside class="conversation-panel"><div class="message-tabs"><button :class="{active:!archivedView&&tab==='messages'}" @click="showInbox">Messages</button><button :class="{active:tab==='requests'}" @click="showRequests">Requests <span v-if="requests.length">{{requests.length}}</span></button><button :class="{active:archivedView&&tab==='messages'}" @click="showArchived">Archived <span v-if="archivedCount">{{archivedCount}}</span></button></div><p v-if="loading">Loading…</p><template v-else><button v-for="(c,i) in tab==='messages'?conversations:[]" class="conversation-item" :class="{active:active?.id===c.id}" @click="select(c)"><span class="conversation-avatar">{{initials(other(c)?.name)}}</span><span class="conversation-copy"><strong>{{other(c)?.name}}</strong><small>{{c.last_message?.body||'Attachment'}}</small></span><b v-if="c.unread_count">{{c.unread_count}}</b><BellOff v-if="c.muted"/></button><button v-for="r in tab==='requests'?requests:[]" class="conversation-item" @click="openRequest(r)"><span class="conversation-avatar">{{initials(r.sender.name)}}</span><span class="conversation-copy"><strong>{{r.sender.name}}</strong><small>{{r.message}}</small></span></button></template></aside><section class="chat-panel"><button type="button" class="mobile-chat-back" @click="closeMobileChat"><ArrowLeft/>Back to inbox</button><template v-if="tab==='requests'&&selectedRequest"><header class="chat-header"><h2>{{selectedRequest.sender.name}}</h2><p>Message request</p></header><div class="request-preview"><span class="conversation-avatar">{{initials(selectedRequest.sender.name)}}</span><p>{{selectedRequest.message}}</p><div class="request-actions"><button class="approve" @click="respond(selectedRequest,'accept')">Approve</button><button @click="respond(selectedRequest,'decline')">Decline</button></div></div></template><template v-else-if="active"><header class="chat-header"><div><h2>{{other(active)?.name}}</h2><p>{{active.archived?'Archived conversation':typingName?typingName+' is typing…':'Real-time conversation'}}</p></div><button @click="controls=!controls"><Settings/></button><div v-if="controls" class="conversation-controls"><button @click="act('mute')"><BellOff/>{{active.muted?'Unmute':'Mute'}}</button><button v-if="active.archived" @click="act('restore')"><Archive/>Restore</button><button v-else @click="act('archive')"><Archive/>Archive</button><button v-if="!active.reported" @click="act('report')"><Flag/>Report</button><button v-if="!active.blocked" @click="act('block')"><UserX/>Block</button></div></header><p v-if="active.archived" class="message-state-note">This conversation is archived. Restore it to your Messages inbox.</p><p v-if="active.reported" class="message-state-note warning"><Flag/>You reported this conversation. Messages remain available as evidence.</p><p v-if="active.blocked" class="message-state-note warning"><UserX/>You blocked this person. New messages are disabled.</p><div ref="thread" class="message-thread"><div v-for="message in messages" :key="message.id" class="message-row" :class="{mine:String(message.sender?.id)===me,deleted:message.deleted_at}" @pointerdown="startMessagePress(message)" @pointerup="cancelMessagePress" @pointercancel="cancelMessagePress" @pointerleave="cancelMessagePress" @contextmenu.prevent="openMessageControls(message)"><span class="message-sender-avatar" :title="messageSender(message).name"><img v-if="messageSender(message).profile_image" :src="messageSender(message).profile_image" :alt="messageSender(message).name"/><span v-else>{{initials(messageSender(message).name)}}</span></span><div class="message-bubble"><img v-if="message.media?.kind==='image'&&!message.deleted_at" :src="message.media.download_url"/><video v-if="message.media?.kind==='video'&&!message.deleted_at" :src="message.media.download_url" controls playsinline/><p v-if="message.deleted_at" class="deleted-message">Message deleted</p><p v-else-if="message.body">{{message.body}}</p><small v-if="message.edited_at&&!message.deleted_at">Edited</small><small v-if="String(message.sender?.id)===me&&!message.deleted_at">{{message.read_at?'Read':'Sent'}}</small></div></div><p v-if="typingName" class="typing-indicator"><i/><i/><i/></p></div><form v-if="!active.blocked&&!active.archived" class="message-composer" @submit.prevent="send"><label><Paperclip/><input type="file" accept="image/jpeg,image/png,image/webp,video/mp4,video/quicktime,video/webm" @change="attachment=($event.target as HTMLInputElement).files?.[0]??null"/></label><span v-if="attachment">{{attachment.name}}<button type="button" @click="attachment=null"><X/></button></span><input v-model="draft" placeholder="Type message…" maxlength="5000"/><button :disabled="sending||(!draft.trim()&&!attachment)">{{sending?'Sending…':'Send'}}</button></form></template><div v-else class="chat-placeholder"><Search/><p>{{archivedView?'No archived conversation selected.':'Select a conversation.'}}</p></div></section></div><div v-if="selectedMessage" class="message-action-overlay" @click.self="selectedMessage=null"><section class="message-action-sheet"><header><div><h2>Message options</h2><p>{{selectedMessage.read_at?'This message has been seen. You can delete it, but editing is no longer available.':'Edit or delete your message.'}}</p></div><button type="button" aria-label="Close" @click="selectedMessage=null"><X/></button></header><form v-if="selectedMessage.body&&!selectedMessage.read_at" @submit.prevent="editMessage"><label>Edit message<textarea v-model="editText" maxlength="5000" autofocus/></label><button class="message-edit-button" :disabled="messageActionBusy||!editText.trim()">Save changes</button></form><button class="message-delete-button" :disabled="messageActionBusy" @click="deleteMessage">Delete message</button></section></div></main></AppShell></template>
